INSERT INTO `info` (`id`, `image`, `title`, `headline`, `description`, `created_at`, `updated_at`) VALUES
(8, NULL, 'Kerjasama Pemasaran Perumahan Gren Natural Huis', 'Event', '<p>Penandatanganan Kerjasama Pemasaran Property Primary dengan Perumahan Gren Natural Huis berlokasi di Cipayung Ciputat Tangerang Selatan</p>', '2025-01-20 13:06:52', '2025-01-21 09:55:53'),
(10, NULL, 'Progress Lapangan Perumahan Shevia Heights Pamulang', 'Info', '<p>Proses pengerjaan pemadatan jalan Perumahan Shevia Heights. Progress pengerjaan sudah mencapai 60%.&nbsp;&nbsp;</p>', '2025-01-21 15:41:45', '2025-01-21 15:46:44'),
(11, NULL, 'Kunjungan Ke Tahomi Ville, Progress Pembangunan Untuk Unit Ready Stock', 'Info', '<p>Team Ara Development Property sedang kunjungan ke <strong>Tahomi Ville, </strong>Tapos Depok. Saat ini sedang berprogres pembangunan 4 unit. Model rumahnya bagus dan cocok buat anak muda atau pasangan muda yang sedang cari rumah. Informasi yang kami dapat proses finishing salah satu unit adalah sekitar 1 bulanan ke depan. Semoga segera selesai, dan konsumen cepat bisa dapat unit ready.</p>', '2025-02-05 15:21:17', '2025-02-05 15:23:18'),
(12, NULL, 'Shevia Heights Progress Per Mei 2025', 'Info', '<p>Perumahan Shevia Heights Pamulang siap dipasarkan, dengan kondisi terkini sudah terbangun Gerbang, Pos Sekuriti. Infrastruktur saluran terus dibangun dan Rumah Contoh sudah masuk pondasi rumah. .</p>', '2025-05-25 09:14:57', '2025-05-25 09:14:57'),
(13, NULL, 'Kabar Terbaru, MRT Akan Menembus Tangsel. Ini Dia Bocorannya!', 'Info', '<p>Berdasarkan <strong><a href=\"https://www.cnbcindonesia.com/news/20250711125921-4-648310/kabar-terbaru-mrt-jakarta-tembus-tangsel-ini-bocorannya\"><span style=\"color:#000000\">Artikel CNBC Indonesia,</span></a></strong> yang mengutip <strong><a href=\"https://finance.detik.com/infrastruktur/d-8005581/pembangunan-mrt-sampai-tangerang-selatan-dikaji-pakai-skema-kpbu\"><span style=\"color:#000000\">detik.com</span></a></strong>, rencana perluasan rute ini telah melewati tahap uji kelayakan oleh Pemerintah Kota (Pemkot) Tangsel. Meski begitu, MRT Jakarta masih mengkaji skema pendanaan pembangunan MRT hingga ke Tangsel. Proyek ini diharapkan dapat berjalan tanpa dana pemerintah.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Kajian sementara PT MRT Jakarta, proyek ini akan mencakup dua koridor potensial, yaitu koridor utara dan selatan. Koridor utara akan melintasi jalur Pondok Aren - Serpong, sedangkan koridor selatan melalui Ciputat - Pondok Cabe. Kedua jalur ini akan terhubung dengan stasiun utama di Lebak Bulus, Jakarta.<br />\r\n<br />\r\nPerpanjangan jalur MRT dari Jakarta sangat penting bagi warga Tangsel. Sebab, sekitar 70% dari 1,5 juta penduduk Tangerang Selatan hilir mudik ke Jakarta.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>(Dok by: <a href=\"https://commons.wikimedia.org/w/index.php?title=User:Alvin_Immanuel&amp;action=edit&amp;redlink=1\" rel=\"noopener\" target=\"_blank\">Alvin Imanuel</a>/Wikipedia)</p>', '2025-08-06 11:06:21', '2025-08-06 11:14:19'),
(14, NULL, 'Pemerintah Lanjutkan Diskon PPN, Properti Masih Jadi Primadona', 'Info', '<p>Mengutip dari Artikel <strong><a href=\"www.idxchannehttps://www.idxchannel.com/market-news/diskon-ppn-diperpanjang-sektor-properti-dinilai-tetap-prospektifl.com/\"><span style=\"color:#000000\">IDX Channel</span></a>, </strong>bahwa pemerintah telah mengumumkan perpanjangan insentif diskon Pajak Pertambahan Nilai (PPN) sebesar 100 persen untuk pembelian properti hingga akhir tahun 2025.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Langkah ini mendapat sambutan positif dari analis BRI Danareksa Sekuritas. Mereka menilai kebijakan tersebut akan terus mendukung kinerja sektor properti, terutama di semester kedua tahun ini.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Dalam laporan riset yang dirilis pada 29 Juli 2025, BRI Danareksa menyebutkan bahwa perpanjangan ini sudah diprediksi sebelumnya. Diskon PPN dianggap sangat membantu meningkatkan daya beli masyarakat, karena dapat mengurangi beban awal pembeli hingga 11 persen.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>(Dok by: Perumahan Shevia Heights)</p>', '2025-08-07 05:50:15', '2025-08-07 05:58:23'),
(15, NULL, 'Cara & Biaya Balik Nama Tanah dari Orang Tua ke Anak', 'Info', '<p style=\"text-align:justify\">Dikutip dari <a href=\"https://www.detik.com/properti/kepemilikan-rumah/d-8104967/mau-balik-nama-tanah-orang-tua-ke-anak-ini-syarat-dan-biayanya\"><span style=\"color:#000000\"><strong>Detik.com</strong></span></a>, Balik nama sertifikat tanah dari orang tua ke anak bisa dilakukan dengan dua cara, yaitu melalui <strong>waris</strong> (setelah orang tua meninggal dunia) atau <strong>hibah</strong> (saat orang tua masih hidup). Proses ini dilakukan di Kantor Pertanahan (BPN) sesuai lokasi tanah agar kepemilikan sah secara hukum dan menghindari potensi sengketa di kemudian hari.</p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><strong>Dokumen yang dibutuhkan antara lain:</strong></p>\r\n\r\n<ul>\r\n	<li>\r\n	<p style=\"text-align:justify\">Formulir permohonan.</p>\r\n	</li>\r\n	<li>\r\n	<p style=\"text-align:justify\">Fotokopi KTP &amp; KK pemohon serta pemberi hak.</p>\r\n	</li>\r\n	<li>\r\n	<p style=\"text-align:justify\">Sertifikat tanah asli.</p>\r\n	</li>\r\n	<li>\r\n	<p style=\"text-align:justify\">SPPT PBB tahun berjalan + bukti bayar PBB.</p>\r\n	</li>\r\n	<li>\r\n	<p style=\"text-align:justify\">Bukti pembayaran BPHTB.</p>\r\n	</li>\r\n	<li>\r\n	<p style=\"text-align:justify\">Surat Keterangan Waris (untuk waris).</p>\r\n	</li>\r\n	<li>\r\n	<p style=\"text-align:justify\">Akta Hibah dari notaris (untuk hibah).</p>\r\n	</li>\r\n</ul>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><strong>Biaya balik nama terdiri dari:</strong></p>\r\n\r\n<ul>\r\n	<li>\r\n	<p style=\"text-align:justify\"><strong>PNBP (Penerimaan Negara Bukan Pajak):</strong> (1/1000 &times; luas tanah &times; nilai tanah/m&sup2;) + Rp50.000.</p>\r\n	</li>\r\n	<li>\r\n	<p style=\"text-align:justify\"><strong>BPHTB (Bea Perolehan Hak atas Tanah dan Bangunan):</strong> 5% dari nilai tanah (berdasarkan NJOP), dikurangi nilai tidak kena pajak sesuai aturan daerah.</p>\r\n	</li>\r\n</ul>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\">Dengan menyiapkan dokumen dan biaya yang sesuai, proses balik nama dapat berjalan lancar serta memberikan kepastian hukum bagi anak sebagai penerima hak tanah.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>(Dok by: <em>Chat GPT Image Generator</em>)</p>', '2025-09-13 06:41:07', '2025-09-13 06:42:17'),
(16, NULL, '💥 Promo Spesial Akhir Tahun! Potongan Rp50 Juta untuk Rumah Dua Lantai Modern di Tangsel!', 'Info', '<h2>🏡 <strong>Shevia Heights Hadirkan Promo Akhir Tahun, Potongan Hingga Rp50 Juta untuk Hunian Dua Lantai di Tangsel</strong></h2>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>Tangerang Selatan (November 2025)</strong> &ndash; PT Mitramas Multi Investindo resmi meluncurkan <em>Program Promo Akhir Tahun</em> untuk proyek hunian <strong>Shevia Heights</strong> yang berlokasi di Bakti Jaya, Setu, Tangerang Selatan. Melalui promo ini, konsumen berkesempatan memperoleh <strong>potongan harga hingga Rp50 juta</strong> untuk setiap pembelian rumah dua lantai bergaya <strong>Tropical Modern</strong>.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Selama periode promo, harga unit <strong>Type 55/75</strong> turun dari <strong>Rp1,03 miliar menjadi Rp982,5 juta</strong>, sudah termasuk seluruh biaya legalitas penting seperti BPHTB, biaya notaris, AJB, asuransi, dan balik nama.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&ldquo;Shevia Heights kami hadirkan untuk memenuhi kebutuhan hunian modern dan strategis bagi keluarga muda serta profesional di wilayah Tangerang Selatan,&rdquo; ujar <strong>Rully</strong>, perwakilan Shevia Heights.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Shevia Heights menawarkan <strong>32 unit rumah</strong> dengan luas bangunan <strong>75 m&sup2;</strong>, <strong>Sertifikat Hak Milik (SHM)</strong>, dan <strong>IMB/PBG</strong>, serta desain <strong>Tropical Modern</strong> yang menonjolkan pencahayaan alami dan tata ruang efisien. Lokasinya yang bebas banjir dan dekat berbagai fasilitas di Pamulang menjadikan proyek ini pilihan menarik di segmen hunian menengah atas.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Untuk memudahkan pembelian, Shevia Heights bekerja sama dengan <strong>BTN</strong> dan <strong>BSI</strong>, menawarkan KPR konvensional maupun syariah dengan bunga tetap 6% selama dua tahun dan cicilan mulai <strong>Rp5 jutaan per bulan</strong>.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Promo berlaku mulai <strong>1 November 2025</strong> untuk unit terbatas. Informasi lebih lanjut dapat diperoleh melalui <strong>tim pemasaran resmi Shevia Heights di 0878 5445 4888</strong></p>', '2025-11-10 06:51:40', '2025-11-10 06:52:39'),
(17, NULL, 'Begini Gambaran Preferensi Masyarakat Saat Mencari Rumah Idaman', 'Info', '<p>Calon pembeli rumah saat ini didominasi oleh usia produktif dengan pendapatan stabil, baik dari pekerjaan tetap, kontrak, maupun usaha rumahan. Sebagian besar masih tinggal bersama keluarga atau menyewa, namun memiliki keinginan kuat untuk memiliki hunian sendiri.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Dalam memilih rumah, <strong>lokasi menjadi faktor paling penting</strong>, terutama yang dekat dengan keluarga, tempat kerja, sekolah anak, atau mudah dijangkau transportasi umum. Harga tetap menjadi pertimbangan, namun bukan satu-satunya faktor.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Untuk pembayaran, banyak calon pembeli memilih <strong>KPR</strong> sebagai opsi paling realistis, sementara sebagian lainnya menggunakan skema cicilan bertahap, pembayaran tunai, atau menggabungkan pendapatan pasangan untuk mempermudah pengajuan.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Wilayah yang paling diminati meliputi <strong>Jakarta, Depok, Tangerang Selatan, Tangerang Kota, dan Bogor</strong>, karena menawarkan akses mudah, fasilitas lengkap, serta potensi kenaikan nilai properti yang menjanjikan.</p>', '2025-12-12 09:08:35', '2025-12-12 09:08:35'),
(18, NULL, 'Sering Dengar Kata COMPACT Dalam Dunia Arsitek, Apa Artinya?', 'Info', '<p>Kata <strong>&quot;Compact&quot;</strong> seringkali disalahartikan sebagai &quot;kecil&quot; atau &quot;sempit&quot;. Padahal, dalam arsitektur modern, <em>compact</em> adalah tentang <strong>efisiensi, kecerdasan ruang, dan gaya hidup yang esensial.</strong></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Jika ada sebuah design menggunakan istilah&nbsp;<em>&#39;Compact&#39;</em> bukan merujuk pada keterbatasan luas, melainkan sebuah pernyataan gaya hidup. Rumah yang compact itu cenderung ruangan terkelola dengan baik sehingga fungsional dan maksimal.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&quot;Mengapa memilih hunian <em>compact</em>? Karena efisiensi adalah kemewahan baru. Desain <em>compact</em>&nbsp;memastikan mobilitas penghuninya menjadi lebih praktis, perawatan rumah menjadi lebih mudah, dan penggunaan energi menjadi lebih hemat. Kami membuktikan bahwa rumah yang efisien tetap bisa tampil megah dengan privasi maksimal dan area multifungsi yang fleksibel.&quot;</p>', '2026-01-21 14:52:08', '2026-02-16 09:52:05');
