INSERT INTO `land` (`id`, `judul`, `lt`, `surat`, `imb`, `harga`, `lokasi`, `kecamatan`, `kota`, `deskripsi`, `video`, `user_id`, `created_at`, `updated_at`) VALUES
(8, 'Kavling Pondok Aren 7 Menit Pasar Modern Bintaro', 150, 'SHM', 'Ya', '5000000', 'Pondok Aren TangSel', 'Pondok Aren', 'Tangerang Selatan', '<p>Kavling Pondok Aren Akses bintaro, dekat dengan fasilitas bintaro, hanya 5 menit. Lokasi strategis, diarea pemukiman, cocok sekali untuk kavling bangun rumah. Dimensi tanah +/- 7.5m x 21m (panjang kedalam dan tdk kotak sekali). lokasi dan fasilitas terdekat : ps modern bintaro sektor 7, bintaro exchange, KRL Jurang mangu, Tol Pondok aren jakarta dan bsd , Rs.Premier Bintaro, Sekolah lokal dan internasional.</p>', NULL, 0, '2025-01-29 14:21:13', '2026-01-30 12:33:19'),
(11, 'Jual Kavling Deret Siap Bangun di Sawangan Depok', 294, 'SHM', 'Ya', '5000000', 'Sawangan Depok', 'Sawangan', 'Depok', '<p>✨ Keunggulan:<br />\r\n- Row jalan besar<br />\r\n- Listrik underground<br />\r\n- SHM + IMB siap<br />\r\n- Dalam cluster &amp; di jalan boulevard</p>\r\n\r\n<p>📏 Luas tanah: total 294 m&sup2; (3 kavling @98 m&sup2; - Dimensi 7m x 14m)<br />\r\n💰 Harga: 5.000.000,-/m&sup2; <strong>(Nego)</strong></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>Lokasi Strategis</strong></p>\r\n\r\n<ul>\r\n	<li>5 Menit Transjakarta Lebak Bulus Sawangan</li>\r\n	<li>10 Menit ke Tol Sawangan</li>\r\n	<li>15 menit ke Stasiun KRL Depok</li>\r\n	<li>15 menit ke kawasan Jagakarsa Jakarta Selatan</li>\r\n	<li>20 menit ke kawasan Tangerang Selatan</li>\r\n	<li>10 menit ke RSUD Depok</li>\r\n	<li>5 menit ke Putri Duyung Waterboom</li>\r\n	<li>15 menit ke Mall D&#39;Park Sawangan</li>\r\n	<li>5 menit ke SMKN 2 Depok</li>\r\n</ul>', NULL, 18, '2025-08-14 13:11:03', '2025-09-15 08:42:32'),
(12, 'Kavling Pamulang 3 Menit Walikota Tangerang Selatan Area Penghunian', 1700, 'SHM', 'Tidak', '3000000', 'Pamulang TangSel', 'Pamulang', 'Tangerang Selatan', '<p>Kavling darat di Pamulang hanya 3 menit ke Walikota Tangerang Selatan. Lokasi Hunian, potensial dikembangkan menjadi cluster, karena di lokasi sudah banyak cluster dibangun. Surat ada 5, untuk SHM seluas 600 m2. Jual putus tidak untuk dikerjasamakan. HARGA 3 Juta per meter.&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>#kavlingpamulang #kavlingtangsel #jualkavling #jualkavlingpamulang #jualkavlingtangsel&nbsp;</p>', NULL, 5, '2025-10-23 13:47:23', '2026-01-30 12:32:58');
