INSERT INTO `perumahan` (`id`, `perumahan`, `lokasi`, `luas`, `unit`, `kota`, `satuan`, `harga`, `harga_asli`, `brosur`, `pricelist`, `img`, `status`, `created_at`, `updated_at`, `keunggulan`, `tipe`, `fasilitas`, `maps`, `deskripsi`, `video`) VALUES
(34, 'Swarna Asri 2', 'Perumahan Sawangan Village, Jl. Raya Muchtar Kelurahan Bedahan Kecamatan Sawangan Kota Depok', 4000, 41, 'Depok', 'Jt', '973', 973000000, 'brosur/NsjCpYOSedbhBjb9f53QJmf2jjtDDCNclSD7wqGM.pdf', 'pricelist/vSykBOyAofFYNfaQ9ceJENL257tNvo1SlKUSDyCF.pdf', NULL, 'Available', '2025-01-17 10:32:50', '2025-08-13 05:50:13', '[\"10 Menit ke Tol Desari\",\"15 Menit ke KRL Depok\",\"5 Menit ke Putri Duyung Water Boom\",\"18 Menit ke D Park Sawangan\",\"4 Menit ke SD AL\'ARAF Indonesia\",\"5 Menit ke SMKN 2 Depok\",\"5 Menit ke RSUD Depok\",\"5 Menit ke RS Permata Depok\"]', '[\"98\\/65\",\"98\\/72\"]', '[\"One Gate system\",\"Sekuriti 24 Jam\",\"Jogging Track, Sarana Olahraga\",\"Taman Perumahan\",\"Listrik Underground\",\"Jaringan Internet\",\"Musholah\"]', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3809.9797498041366!2d106.7638576748049!3d-6.412416793578431!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x2e69e9fed69fffa3%3A0xb595bb43d2f90fea!2sSwarna%20Asri%20Block%20C!5e1!3m2!1sid!2sid!4v1732875159556!5m2!1sid!2sid', '<p>Cluster hunian yang dibangun exclusive dengan memperhatikan keseimbangan antara lingkungan yang asri, desain yang modern serta dapat memberikan kenyamanan tinggal bagi keluarga sehingga dapat menghadirkan sebuah harmoni.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>WHY SWARNA ASRI 2 ?</strong></p>\r\n\r\n<ul>\r\n	<li>- Dibangun di kawasan berkembang yang akan meningkatkan nilai jual di masa depan, cocok sebagai investasi</li>\r\n	<li>- Dibangun menggunakan spesifikasi bangunan dan material yang baik, juga menggunakan bata merah sebagai material utama.</li>\r\n	<li>- Jalan dibuat menggunakan Paving Block yang dapat menyerap air dan akses untuk kendaraan bisa 2 mobil.</li>\r\n</ul>\r\n\r\n<p>​​​​​​</p>\r\n\r\n<p><strong>​Fasilitas Pembelian&nbsp; :</strong></p>\r\n\r\n<ul>\r\n	<li><strong>- Free Biaya Legalitas (BPHTB, Notaris, KPR, BN)</strong></li>\r\n	<li><strong>- Payment KPR, Cash</strong></li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>Spesifikasi</strong></p>\r\n\r\n<ul>\r\n	<li>Unit 1 lantai :&nbsp;L.T/L.B : 94-104/45-65</li>\r\n	<li>Unit 2 lantai :&nbsp;L.T/L.B : 98/72,KT/KM 2/3</li>\r\n	<li>Air : Jetpump+Toren</li>\r\n	<li>Listrik : 2200 Watt ( underground)</li>\r\n	<li>Carport : 1</li>\r\n	<li>Sertifikat : SHM /IMB</li>\r\n	<li>Bisa Custom Layout</li>\r\n	<li>Tersedia luas tanah yang lebih besar</li>\r\n</ul>\r\n\r\n<p><br />\r\n<strong>BONUS</strong></p>\r\n\r\n<ul>\r\n	<li>Free Smart Door Lock</li>\r\n	<li>Free AC 1/2 PK</li>\r\n	<li>Free CCTV</li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>SURVEY LOKASI&nbsp;bisa janjian melalui website sekarang, isi hari dan jam yang diinginkan.</p>', 'https://www.youtube.com/embed/AVhV_ULiz-c'),
(35, 'Azzura Sawangan', 'Perumahan Sawangan Village, Jl. Raya Muchtar Kelurahan Bedahan Kecamatan Sawangan Kota Depok', 3000, 36, 'Depok', 'Jt', '660', 660000000, 'brosur/LYKsntdXXWlByN2ygImofuCBMoZhawspjzFN2xnA.pdf', 'pricelist/XetmlMBUZv82BwxVUFJ5uifHrRn5KG4u7GV7IAAA.pdf', NULL, 'Available', '2025-01-17 10:45:51', '2025-09-01 07:09:14', '[\"5 Menit Transjakarta Lebak Bulus Sawangan\",\"10 Menit ke Tol Sawangan\",\"15 menit ke Stasiun KRL Depok\",\"15 menit ke kawasan Jagakarsa Jakarta Selatan\",\"20 menit ke kawasan Tangerang Selatan\",\"10 menit ke RSUD Depok\",\"5 menit ke Putri Duyung Waterboom\",\"15 menit ke Mall D\'Park Sawangan\",\"5 menit ke SMKN 2 Depok\"]', '[\"60\\/36\",\"60\\/70\"]', '[\"One Gate system\",\"Sekuriti 24 Jam\",\"Jogging Track, Sarana Olahraga\",\"CCTV Perumahan\",\"Mushola\"]', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d145019.25194962043!2d106.63213172641089!3d-6.296355073500554!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x2e69e90026a28e81%3A0x1885b2cd4452a6a5!2sAzzura%20Sawangan!5e1!3m2!1sen!2sid!4v1751633519880!5m2!1sen!2sid', '<p>Produk terbaru dari kami dengan konsep rumah minimalis modern cocok untuk para milenials. Rumah 1 lantai dan 2 lantai.</p>\r\n\r\n<p><strong>Spesifikasi Azzura :</strong></p>\r\n\r\n<ul>\r\n	<li>- Ruang Tamu</li>\r\n	<li>- Kamar Utama</li>\r\n	<li>- Kamar Anak</li>\r\n	<li>- Kamar Mandi</li>\r\n	<li>- Dapur</li>\r\n	<li>- Tangga Lipat</li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>Fasilitas Pembelian&nbsp; :</strong></p>\r\n\r\n<ul>\r\n	<li><strong>- Free Biaya Legalitas (BPHTB, Notaris, KPR, BN)</strong></li>\r\n	<li><strong>- Payment KPR, Cash</strong></li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>SURVEY LOKASI&nbsp;bisa janjian melalui website sekarang, isi hari dan jam yang diinginkan.</p>', 'https://www.youtube.com/embed/LTLjmwvqldY'),
(36, 'Shevia Heights', 'Jl. Baru Luk Bakti Jaya Setu', 4889, 32, 'Tangerang Selatan', 'Jt', '1078.5', 1078500000, 'brosur/l6Ww2f8YgItdTSRVn88fwu1OQ6d0E1DrBb8LrFRG.pdf', 'pricelist/XHztxPrNM3pAchs2UvxTjACKmkLFmdGtOyJ6omYR.pdf', NULL, 'Available', '2025-01-17 13:02:02', '2025-11-04 04:48:41', '[\"9 Menit ke Pamulang Square\",\"9 Menit ke Mall Paradise Walk Serpong\",\"9 Menit ke Global Islamic School 2 Serpong\",\"8 Menit ke Universitas Pamulang 2\",\"7 Menit ke RS Permata Pamulang\",\"10 Menit ke RS Hermina Hospital Serpong\",\"20 Menit ke Tol Bsd - Bintaro\",\"22 Menit ke St Rawa Buntu\"]', '[\"62\\/75A\",\"64\\/75B\"]', '[\"One Gate system\",\"Sekuriti 24 Jam\",\"CCTV Perumahan\",\"Communal Area\",\"Internet Koneksi\"]', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3965.32384567129!2d106.70668227480434!3d-6.352103593637824!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x2e69e50031a9bb79%3A0x541c82f4ee4799ce!2sShevia%20Heights!5e0!3m2!1sid!2sid!4v1733404509203!5m2!1sid!2sid', '<p><strong>Shevia Heights</strong> adalah perumahan dengan konsep <strong>Tropicality Meet Modernity</strong>, mengusung sebuah keseimbangan antara tropical dan modern. Rumah dengan banyak bukaan cahaya dan sistem sirkulasi udara yang baik dengan gaya bangunan modern.</p>\r\n\r\n<p><strong>Shevia Heights</strong> menawarkan 2 Type rumah dengan model dan kelebihan masing-masing. Tipe 75A dengan lebar 6.5 dan Tipe 75B dengan lebar 8.&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>Spesifikasi Ruang :</strong></p>\r\n\r\n<ol>\r\n	<li>Bedroom 3</li>\r\n	<li>Bathroom 3</li>\r\n	<li>Living Room</li>\r\n	<li>Dining Room</li>\r\n	<li>Multifuction Room</li>\r\n	<li>Kitchen</li>\r\n	<li>Service Area</li>\r\n	<li>Backyard Garden</li>\r\n	<li>Balcony</li>\r\n	<li>Carport</li>\r\n	<li>Garden</li>\r\n</ol>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Harga yang kami tawarkan <strong>ALL IN</strong>, sudah meliputi semua biaya-biaya, termasuk KPR dan Balik Nama (BN)</p>\r\n\r\n<p>Sistem payment kami bisa dengan KPR dan Cash Keras</p>', 'https://youtu.be/ROf6KTtvDag'),
(37, 'Gren Natural Huis', 'Jl Citarum Raya No 27 Cipayung Ciputat', 2000, 15, 'Tangerang Selatan', 'Jt', '1400', 1575000000, 'brosur/XgFKicUluPgJNor0kA2Fiq73XHI66KKFe9dKN1xO.pdf', 'pricelist/fQSBN99peFsQnF5CMcHvEG3O4cpJejx12yIFTC5b.pdf', NULL, 'Available', '2025-01-20 13:39:05', '2025-07-05 14:39:32', '[\"3 Menit Ke Transjakarta Ciputat\",\"10 Menit Ke Pintu Tol Pondok Cabe\",\"20 Menit Ke MRT Lebak Bulus\",\"20 Menit Ke St Jurang Mangu\",\"7 Menit Ke RS Sari Asih\",\"10 Menit Ke RS UIN\",\"10 Menit Ke Kampus UIN\"]', '[\"62\\/90\",\"81\\/107\"]', '[\"One Gate system\",\"Sekuriti 24 Jam\",\"CCTV Perumahan\",\"Taman Anak\"]', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3965.5890874236034!2d106.74703237480409!3d-6.317582593671811!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x2e69efe26256b315%3A0x7e09f7ab3e68cd35!2sGren%20Natural%20Huis!5e0!3m2!1sid!2sid!4v1737380174303!5m2!1sid!2sid', '<p><strong>Gren Natural Huis</strong> Perumahan dan property&nbsp;konsep yang menawarkan gaya hidup modern yang nyaman dan lingkungan yang indah bagi keluarga Anda. Ini mencakup desain rumah ramah lingkungan, ruang terbuka hijau, fasilitas kesehatan dan rekreasi, serta keamanan yang terjamin. Eksklusif hanya 15 Unit dan semua memiliki Rooftop.&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>SURVEY LOKASI&nbsp;bisa janjian melalui website sekarang, isi hari dan jam yang diinginkan.</p>', 'https://youtu.be/zA6i8Gs70IM?si=awGhQLWacwzlpmbK'),
(38, 'Tahomi Ville', 'Jl Sedap Malam Cimpaeun Tapos', 2500, 17, 'Depok', 'Jt', '800', 818979496, 'brosur/Af8HvvZ1YD0auxke2gOEP3DbxguvYcKYCPsePR9d.pdf', 'pricelist/GGyxRSOg78TOfsOKYFL4h9DwkbRNUvKtxUnwNING.pdf', NULL, 'Available', '2025-01-23 04:11:53', '2026-03-04 08:33:43', '[\"7 Menit ke Gerbang Tol Cimanggis\",\"8 Menit ke LRT Podomoro\",\"7 Menit ke Golf Cimanggis\",\"20 Menit ke Transmart Cibubur\",\"23 Menit ke Margo City\",\"25 Menit ke Aeon Tanjung Barat\",\"30 Menit ke SCBD\",\"35 Menit ke Halim Perdana Kusuma\",\"40 Menit ke Bandara Soeta\"]', '[\"66\\/55\",\"70\\/80\",\"121\\/80\"]', '[\"One Gate system\",\"Sekuriti 24 Jam\",\"CCTV Perumahan\",\"Taman Perumahan\"]', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3964.6534903709453!2d106.881495!3d-6.4385281999999995!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x2e69eb0068c144d9%3A0x3c05740aaa61d35f!2sTahomi%20Ville!5e0!3m2!1sid!2sid!4v1737605353116!5m2!1sid!2sid', '<p>Tahomi Ville merupakan hunian Perumahan yang memiliki total 17 unit rumah. Dengan dilengkapi keamanan 24 jam serta One Gate System, Communal Garden Space Dan Playground serta CCTV untuk meningkatkan kenyamanan penghuni</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>BONUS</strong> :</p>\r\n\r\n<p>Free BPHTB✅<br />\r\nFree AJB ✅<br />\r\nBisa DP 0%✅<br />\r\nFree Smart Door Lock✅<br />\r\nFree CCTV✅</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>SURVEY LOKASI&nbsp;bisa janjian melalui website sekarang, isi hari dan jam yang diinginkan.</p>', NULL),
(39, 'New Melati Hills', 'Jl Pengasinan Raya Sawangan', 10000, 50, 'Depok', 'Jt', '400', 40000000, 'brosur/HQwSIGidKrxI0I09xXeeNpidUkM50ff9nV5PAsGa.pdf', 'pricelist/8HXV2xLSaZdeyQ4s3dHEn5rKglgRDSEEpy1MAb6O.pdf', NULL, 'Available', '2025-02-03 16:08:03', '2025-05-30 08:09:37', '[\"5 Menit RSUD\",\"20 Menit DTC\",\"15 Menit The Park Sawangan\",\"15 Menit Tol Desari\",\"20 Menit Tol Pamulang\",\"20 Menit Bandara Pondok Cabe\"]', '[\"60\\/32\",\"60\\/60\",\"84\\/36\",\"90\\/60\"]', '[\"Lapangan Badminton\",\"Lapangan Basket\",\"Lapangan Futsal\",\"Mesjid\",\"Sekuriti 24 Jam\",\"Taman\"]', 'https://www.google.com/maps/embed?pb=!1m17!1m12!1m3!1d3964.8259939559707!2d106.75078567499202!3d-6.416399193574471!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m2!1m1!2zNsKwMjQnNTkuMCJTIDEwNsKwNDUnMTIuMSJF!5e0!3m2!1sen!2sid!4v1738598699201!5m2!1sen!2sid', '<p><strong>New Melati Hills</strong>, Perumahan dengan akses 3 jalan utama, 4 jalan tol. Perumahan dengan berbagai fasilitas. Perumahan ini menawarkan beberapa tipe rumah dengan layout dan tampilan maksimal. Beberapa tipe tersebut adalah :</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>TIPE VISTA : 60/32 untuk 1 lantai , 60/60 untuk 2 lantai</strong></p>\r\n\r\n<p><strong>TIPE VILLA : 84/36 untuk 2 lantai , 90/60 untuk 2 lantai</strong></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>BOOKING 1 JT , RESERVASI 300 Ribu</strong> (sisanya 700 Ribu menjadi BOOKING). Saat RESERVASI masuk sudah bisa menentukan unit yang diinginkan. Jangka waktu 1 Bulan untuk pengumpulan data konsumen.&nbsp;</p>\r\n\r\n<p>BOOKING Kembali 50% jika data konsumen ditolak KPR nya oleh BANK.&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>SURVEY LOKASI</strong> bisa janjian melalui website sekarang, isi hari dan jam yang diinginkan.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>Bonus :</strong></p>\r\n\r\n<ul>\r\n	<li><strong>DP 0%</strong></li>\r\n	<li><strong>FREE Biaya-biaya / ALL IN</strong></li>\r\n	<li><strong>Smart Door Lock</strong></li>\r\n	<li><strong>Cash Back 5 Juta&nbsp;Rupiah</strong></li>\r\n</ul>', 'https://youtu.be/Y2Q6yz0xyPU?si=HmbReFiKw7jvX8IQ'),
(40, 'Aleka Residence', 'Jl Rean Serua Pamulang', 1000, 10, 'Tangerang Selatan', 'Jt', '740', 740000000, 'brosur/KbR4LJIJWG5xZ1zODLjMXzwxBjfBY8kRIY64f6kl.pdf', 'pricelist/OK34PBZMbnTesnAyeAv2jXTqYexHXyxb8rxvydaa.pdf', NULL, 'Available', '2025-05-04 03:33:26', '2025-11-17 03:10:09', '[\"5 menit RS. Sariasih Ciputat\",\"5 menit Univ. Pamulang\",\"10 menit tol Pamulang\",\"15 menit St. Sudimara\"]', '[\"54\\/65\"]', '[\"One Gate system\",\"Sekuriti 24 Jam\",\"CCTV Perumahan\",\"Smart Door Lock\"]', 'https://www.google.com/maps/embed?pb=!1m17!1m12!1m3!1d3965.508968371005!2d106.72019337499128!3d-6.328029793661542!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m2!1m1!2zNsKwMTknNDAuOSJTIDEwNsKwNDMnMjIuMCJF!5e0!3m2!1sen!2sid!4v1746330247559!5m2!1sen!2sid', '<p><strong>Brand New Scandinavian&nbsp;</strong><br />\r\nDesign Scandinavian (High ceiling)<br />\r\nPamulang, Tangsel</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>HARGA 700 Jutaan</strong></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>Promo :</strong><br />\r\n* DP 0%<br />\r\n* Free BPHTB, AJB, BN, Notaris<br />\r\n&bull; Smartdoorlock</p>\r\n\r\n<p><br />\r\n<strong>Detail spek :</strong><br />\r\n* Bangunan 1,5 Lantai<br />\r\n* Luas tanah 61 - 78 m&sup2;<br />\r\n* Luas bangunan 54&nbsp;<br />\r\n* Kamar tidur 3 (1.5 lantai)<br />\r\n* Kamar mandi 1 dibawah<br />\r\n* Carport 1 mobil<br />\r\n* Listrik 2200 Watt<br />\r\n* Toren<br />\r\n* Dak toren<br />\r\n* Air sumur bor<br />\r\n* Jet pump</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>Cara bayar :</strong><br />\r\n* Cash keras<br />\r\n* KPR<br />\r\n&nbsp;</p>', NULL),
(41, 'Chi Residence', 'Jl. Sumatra No.77, Jombang, Ciputat', 1200, 9, 'Tangerang Selatan', 'Jt', '1700', 1700000000, 'brosur/JjaDknBw1oKR4tQqL4oDjVDg6ibyKZYXuofMBdW1.pdf', 'pricelist/JE7S1Q4Ef2STCrwINxo7uwG8N2EEFA2BfGmVPCcm.pdf', NULL, 'Available', '2025-07-21 15:18:41', '2025-07-21 15:18:41', '[\"6 Menit St Sudimara\",\"12 Menit Gerbang Tol Pondok Aren\",\"15 Menit Mall Bintaro Exchange\",\"11 Menit Pasar Modern BSD\"]', '[\"78\\/90\"]', '[\"One Gate system\",\"Sekuriti 24 Jam\",\"CCTV Perumahan\"]', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3810.845497809326!2d106.6961020749909!3d-6.29549619369356!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x2e69fbd2c5913533%3A0xc28a0dcc0aaa8ab5!2sCHI%20Residence%20Bintaro!5e1!3m2!1sen!2sid!4v1753111026455!5m2!1sen!2sid', '<p>Cluster Eksklusif area Bintaro - BSD, limited hanya 9 unit, dekat dengan berbagai fasilitas bintaro dan bsd. Spesifikasi : Kamar 3 K.mandi 2, Inner Garden, Balkon.</p>', NULL),
(42, 'Terrawood Bintaro', 'Kavling Deplu Pondok Karya Pondok Aren', 2100, 21, 'Tangerang Selatan', 'Jt', '1300', 1300000000, 'brosur/1V3ZrjwBl1TUp8RSkXsrllHeeBjAN4BDOkgjdJKd.pdf', NULL, NULL, 'Available', '2025-12-10 10:31:55', '2025-12-10 11:56:17', '[\"5 Menit Tranjakarta Cileduk - Tendean\",\"10 Menit Stasiun Pondok Ranji\",\"10 Menit Pintu Tol Pesanggrahan\"]', '[\"110\\/75\",\"120\\/78\"]', '[\"Urban Farming\",\"Mini Aviary\",\"Urban Playground\",\"Parkir Tamu\",\"Eco Friendly: biopori & bank sampah\"]', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d1134.4404713021727!2d106.74182554800662!3d-6.251723039693658!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x2e69f0927f596d7d%3A0xa3ee39231f892861!2sBakmi%20Aseng%20Halal!5e1!3m2!1sen!2sid!4v1765362566606!5m2!1sen!2sid', '<p><strong>TERRAWOOD BINTARO &ndash; Cluster Tropis Urban Eksklusif</strong><br />\r\nHunian tropis modern dengan functional layout, menghadirkan kenyamanan dan ketenangan di lokasi strategis Pondok Aren, Tangerang Selatan.&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>Keunggulan Utama</strong><br />\r\n* Desain Tropis Urban Modern &ndash; pencahayaan optimal &amp; ruang yang efisien<br />\r\n* Keamanan 24 Jam &ndash; one gate system + CCTV</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>Fasilitas Komunitas:</strong><br />\r\n* Urban Farming<br />\r\n* Mini Aviary<br />\r\n* Urban Playground<br />\r\n* Parkir Tamu<br />\r\n* Eco Friendly: biopori &amp; bank sampah</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>Lokasi Strategis</strong><br />\r\nDekat berbagai fasilitas penting seperti sekolah (Al Azhar, Ricci, Budi Luhur), RSUD Pesanggrahan, Stasiun Pondok Ranji, Tol Veteran&ndash;Petukangan, Bintaro Plaza, Pondok Indah Mall, Senayan, serta akses Transjakarta Ciledug&ndash;Tendean (Halte Universitas Budi Luhur).</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>Pilihan Tipe Rumah :</strong></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>Tipe 75 &ndash; LT 100/110</strong><br />\r\n3 KT | 3 KM | 2 Carport | Living &amp; Dining Area | Pantry | Backyard</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>Tipe 78 &ndash; LT 104/120</strong><br />\r\n3+1 KT | 3 KM | 2 Carport | Multifunction Area | Balcony | Open Space</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>Terrawood Bintaro adalah pilihan ideal untuk keluarga modern yang mencari hunian eksklusif, nyaman, dan dekat pusat kota.</strong></p>', NULL),
(43, 'Naputa Residence', 'Jl Aria Putera Kedaung Ciputat', 1300, 14, 'Tangerang Selatan', 'Jt', '1500', 1520000000, 'brosur/iGsGFL0GNlyPZWt2mDpQSht0ByGzuEIZg9UoKkyR.pdf', 'pricelist/UZ5KuSVrvkVLzoXlmSsmGGQfoVS26QNy1VjTfgDs.pdf', NULL, 'Available', '2025-12-15 07:55:43', '2025-12-15 16:07:30', '[\"10 Menit KRL St Sudimara\",\"15 Menit MRT Lebak Bulus\",\"5 Menit Tranjakarta Ps Ciputat\"]', '[\"60\\/85\",\"62\\/85\",\"68\\/85\"]', '[\"One Gate system\",\"Sekuriti 24 Jam\",\"CCTV Perumahan\",\"Communal Area\"]', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3810.692455118532!2d106.73716997480415!3d-6.316318993673089!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x2e69ef803072a977%3A0x353de2c9add1ebfd!2sNAPUTA%20Residence%20by%20ZAFLAND!5e1!3m2!1sen!2sid!4v1765785156279!5m2!1sen!2sid', '<p>*🏡 <strong>Naputa</strong> <strong>Residence</strong> &ndash; Hunian Strategis di Ciputat*</p>\r\n\r\n<p>Rasakan kenyamanan tinggal di Naputa Residence, hunian modern dengan lokasi strategis di Ciputat, Tangerang Selatan. Cocok untuk tempat tinggal maupun investasi. Rumah Compact yang fungsional dengan pencahayaan dan sirkulasi udara yang baik.</p>\r\n\r\n<p>*🏡 <strong>Informasi</strong> <strong>Properti</strong>*<br />\r\n* Lokasi: Ciputat, Tangerang Selatan<br />\r\n* Luas Tanah (LT): 60 m&sup2;<br />\r\n* Luas Bangunan (LB): 85 m&sup2;</p>\r\n\r\n<p>*🎁 <strong>Promo</strong> <strong>Customer</strong>*<br />\r\n* Booking Fee Rp2,5 juta<br />\r\n* Gratis BPHTB<br />\r\n* Gratis AJB<br />\r\n* Gratis Balik Nama<br />\r\n* Gratis Biaya Notaris<br />\r\n* Gratis SHM<br />\r\n* DP 0%</p>\r\n\r\n<p>*🎊 <strong>Bonus</strong> <strong>Akhir</strong> <strong>Tahun</strong>*<br />\r\n* Gratis Smart Door Lock<br />\r\n* Gratis Kitchen Set &amp; Wastafel Cabinet senilai Rp25 juta<br />\r\n* Dan berbagai bonus menarik lainnya 🔥🔥</p>\r\n\r\n<p>*🚗 <strong>Akses</strong> <strong>Lokasi</strong>*<br />\r\n* 3 menit ke Pasar &amp; Plaza Ciputat<br />\r\n* 10 menit ke Pintu Tol Pamulang<br />\r\n* 20 menit ke MRT Lebak Bulus</p>\r\n\r\n<p>*📲 Info selengkapnya silahkan hubungi nomor berikut*<br />\r\n+<strong>62</strong> <strong>878</strong>-<strong>5445</strong>-<strong>4888</strong></p>', NULL);
