(7, 41, 'Rully', 'FU1', '2025-05-21', 'Respon', 'Minta Pricelist Dan informasinya akan survey langsung. Sudah diinfo ke marketing NMH a.n klien tsb utk dibantu saat ke lokasi.', NULL, '2025-05-23 04:04:39', '2025-05-23 04:04:39', '081808961101'),
