(25, 81, 'Rully', 'FU1', '2026-01-03', 'Prospek', 'Konsumen sudah lihat rumah, sudah dijelaskan, pegang brosur dan PL, tertarik unit 32. Minta harga spesial.', NULL, '2026-01-03 09:21:38', '2026-01-03 09:21:38', '08131181990'),
(26, 88, 'Rully\nRully', 'FU1\nFU2', '2026-01-11', 'Prospek\nSent', 'Sudah visit lokasi ditemani pak rully dan pak sidik. Rencana beli cash, suka yg hadap selatan, sedang dipertimbangkan. Sdh pegang PL dan Brosur\nKirim Undangan untuk kunjungan kembali melihat rumah contoh', NULL, '2026-01-11 08:28:46', '2026-02-27 10:05:29', '082118255933'),
