(65, '10651125', 'Dijual', 'Second', 'Available', 'Dijual Rumah di Samasta Citayam 2 – Hunian Nyaman Sudah Renov, Lokasi Strategis!', 90, 30, 2, 0, 1, 0, 1, 0, 1300, 'Sumur Bor', 'SHM', 'Ya', 'Timur', 'Hook', 'Unfurnished', 1, '570000000', 'Jl. Ragajaya, Kelurahan Ragajaya, Kecamatan Bojong Gede, Kabupaten Bogor, Jawa Barat', 'Bojong Gede', 'Bogor', '<p><strong>🏡 Rumah Dijual di Samasta Citayam 2 &ndash; Hunian Nyaman Sudah Renov, Lokasi Strategis!</strong></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>✨ Spesifikasi:</strong><br />\r\n📐 Luas Tanah: 90 m&sup2;<br />\r\n🏠 Luas Bangunan: 30 m&sup2; (Sudah Renov)<br />\r\n🛏️ 2 Kamar Tidur<br />\r\n🚿 1 Kamar Mandi<br />\r\n🚗 Carport<br />\r\n⚡ Listrik: 1300 Watt<br />\r\n💧 Sumur Bor: 20 Meter<br />\r\n🧭 Hadap Selatan<br />\r\n🏡 Posisi Hoek (Hook Unit)<br />\r\n🚪 Unfurnished</p>\r\n\r\n<p><br />\r\n<strong>📍 Lokasi Strategis Dekat Dengan:</strong><br />\r\n🚉 Stasiun Citayam &amp; Stasiun Bojong Gede &ndash; &plusmn;10&ndash;15 menit<br />\r\n🏫 Sekolah &amp; Madrasah Negeri/Swasta &ndash; &plusmn;5&ndash;10 menit<br />\r\n🛒 Pasar Citayam &amp; Bojonggede &ndash; &plusmn;10 menit<br />\r\n🏥 Klinik &amp; RS Umum Daerah &ndash; &plusmn;10&ndash;15 menit<br />\r\n🛣️ Jalan Raya Citayam &ndash; Bojonggede &ndash; Cibinong &ndash; hanya &plusmn;5 menit<br />\r\n🏬 Cibinong City Mall &amp; Depok Town Center &ndash; &plusmn;20&ndash;25 menit</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>💰 Harga: Rp 570 Juta (Nego)</strong></p>', NULL, 18, '2025-11-08 08:16:01', '2025-11-08 08:23:09'),
(66, '20660126', 'Disewakan', 'Second', 'Rented', 'Rumah Sewa Lake Wood 2 Lantai Cozy', 80, 78, 2, 0, 2, 0, 1, 0, 2200, 'Jet Pump', 'SHM', 'Ya', 'Timur', 'Badan', 'Semi Furnished', 2, '39000000', 'Lake Wood Residence Pondok Ranji', 'Ciputat Timur', 'Tangerang Selatan', '<p>Rumah Sewa Semi Furnished 2 lantai, berada di kawasan pemukiman, dekat dengan banyak cluster di Pondok Ranji Ciputat. Dekat dengan berbagai fasilitas seperti transportasi masal KRL - Pondok Ranji / Jurang Mangu, MRT Lebak Bulus, Tansjakarta Ciputat, Mall Bintaro Plaza / Mall Exchange Bintaro, Kampus UIN, sekolah internasional, rumah sakit dll</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>#lakewoodresidence #rumahsewaciputat #rumahsewabintaro #rumahsewacluster&nbsp;</p>', NULL, 5, '2026-01-20 14:47:12', '2026-02-11 14:16:23');
