INSERT INTO `services` (`id`, `judul`, `image`, `short_desc`, `long_desc`, `no_hp`, `created_at`, `updated_at`) VALUES
(2, 'Design Arsitek', 'banner-service/4mMJpUQci7NCaK8o6nIA8FUzDzxVvW8pZtHm2suF.png', 'Ciptakan Hunian & Properti Impian dengan Sentuhan Arsitektur Profesional', '<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>DESAIN ARSITEK BERKELAS UNTUK HUNIAN &amp; PROPERTI KOMERSIAL ANDA</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Membangun properti bukan sekadar mendirikan bangunan, tetapi tentang <strong>menciptakan ruang yang nyaman, fungsional, dan estetis</strong>. Kami hadir untuk membantu Anda mewujudkan impian memiliki hunian atau properti komersial yang tidak hanya menarik secara visual, tetapi juga memiliki <strong>nilai investasi tinggi dan desain yang berorientasi pada kenyamanan penggunanya</strong>.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Sebagai penyedia jasa <strong>Design Arsitek</strong> profesional, kami telah berpengalaman dalam menangani berbagai proyek <strong>residensial maupun komersial</strong>, mulai dari <strong>rumah tinggal, ruko, perkantoran, caf&eacute;, restoran, hingga villa dan resort eksklusif</strong>. Dengan kombinasi kreativitas, perencanaan matang, dan pemahaman mendalam akan tren arsitektur terkini, kami siap menghadirkan desain terbaik yang sesuai dengan karakter dan kebutuhan Anda.</span></span></p>\r\n\r\n<div style=\"margin-bottom:11px; text-align:center\">&nbsp;</div>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>KENAPA HARUS MEMILIH JASA DESIGN ARSITEK KAMI?</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">✔</span> <strong>Desain yang Eksklusif &amp; Berkarakter</strong><br />\r\nSetiap proyek memiliki <strong>identitas unik</strong>. Kami tidak sekadar menggambar bangunan, tetapi merancangnya dengan pendekatan <strong>estetika, fungsionalitas, dan keunikan konsep</strong>, sehingga hasil akhirnya benar-benar mencerminkan kepribadian dan kebutuhan Anda.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">✔</span> <strong>Fungsional &amp; Optimal dalam Tata Ruang</strong><br />\r\nSebuah desain yang baik harus memberikan <strong>kenyamanan bagi penghuninya</strong>. Kami memastikan bahwa setiap ruangan yang dirancang memiliki <strong>proporsi yang tepat, pencahayaan alami yang optimal, serta sirkulasi udara yang baik</strong>, sehingga menciptakan hunian yang sehat dan efisien.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">✔</span> <strong>Efisiensi Biaya &amp; Material</strong><br />\r\nKami memahami bahwa pembangunan properti adalah investasi besar. Oleh karena itu, kami menyusun desain yang <strong>memaksimalkan penggunaan material, mengoptimalkan budget, dan memastikan pembangunan berjalan efisien tanpa mengurangi kualitas</strong>.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">✔</span> <strong>Visualisasi 3D yang Realistis</strong><br />\r\nKesulitan membayangkan hasil akhir properti Anda? Dengan teknologi <strong>rendering 3D yang detail dan realistis</strong>, kami membantu Anda melihat tampilan akhir desain sebelum pembangunan dimulai, sehingga Anda dapat memastikan bahwa semua elemen sudah sesuai dengan harapan.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">✔</span> <strong>Berorientasi pada Kenyamanan &amp; Nilai Investasi</strong><br />\r\nKami tidak hanya membuat desain yang indah, tetapi juga <strong>meningkatkan nilai properti dalam jangka panjang</strong>. Baik untuk hunian pribadi maupun properti komersial, desain yang baik akan memberikan <strong>keuntungan investasi yang lebih besar</strong> di masa depan.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">✔</span> <strong>Fleksibel Sesuai Kebutuhan Klien</strong><br />\r\nKami memahami bahwa setiap klien memiliki <strong>preferensi dan kebutuhan unik</strong>. Oleh karena itu, kami menawarkan pendekatan yang fleksibel dan siap menyesuaikan desain dengan gaya arsitektur yang Anda inginkan, baik itu <strong>minimalis modern, klasik elegan, tropis, industrial, maupun kontemporer</strong>.</span></span></p>\r\n\r\n<div style=\"margin-bottom:11px; text-align:center\">&nbsp;</div>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>LAYANAN DESIGN ARSITEK YANG KAMI TAWARKAN</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>1. Desain Rumah Tinggal</strong></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Mewujudkan hunian yang nyaman, fungsional, dan memiliki estetika tinggi sesuai dengan kebutuhan penghuni. Kami menyediakan desain untuk:<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🏡</span> Rumah minimalis modern<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🏡</span> Rumah klasik &amp; mewah<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🏡</span> Rumah tropis &amp; industrial<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🏡</span> Villa &amp; resort pribadi</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>2. Desain Properti Komersial</strong></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Menciptakan bangunan komersial yang menarik secara visual, meningkatkan daya tarik bisnis, dan fungsional bagi penggunanya. Layanan kami mencakup:<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🏢</span> Ruko &amp; perkantoran<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">☕</span> Caf&eacute; &amp; restoran<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🏨</span> Villa &amp; resort komersial<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🏪</span> Showroom &amp; retail</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>3. Desain Renovasi &amp; Ekstensi Bangunan</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Ingin mengubah tampilan atau menambah luas bangunan tanpa mengubah struktur utama? Kami siap membantu dengan desain renovasi yang <strong>menyelaraskan bangunan lama dengan konsep baru</strong>, meningkatkan fungsi ruang, dan mempercantik tampilan keseluruhan.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>4. Desain Interior &amp; Eksterior</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Setiap ruang memiliki jiwa dan atmosfernya sendiri. Kami membantu mendesain interior &amp; eksterior dengan <strong>perpaduan warna, material, dan pencahayaan</strong> yang menciptakan suasana sesuai keinginan Anda.</span></span></p>\r\n\r\n<div style=\"margin-bottom:11px; text-align:center\">&nbsp;</div>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>PROSES KERJA DESIGN ARSITEK BERSAMA KAMI</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">📌</span> 1. Konsultasi Awal</strong><br />\r\nKami akan mendengarkan keinginan, kebutuhan, dan konsep yang Anda inginkan. Jika belum memiliki gambaran, kami siap memberikan rekomendasi terbaik sesuai dengan luas lahan, fungsi bangunan, dan gaya arsitektur yang cocok.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">📌</span> 2. Perencanaan &amp; Sketsa Awal</strong><br />\r\nTim kami akan membuat sketsa konsep berdasarkan hasil konsultasi, yang mencakup tata ruang, bentuk bangunan, dan aspek estetika lainnya.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">📌</span> 3. Desain 3D &amp; Rencana Teknis</strong><br />\r\nSetelah konsep awal disetujui, kami akan membuat <strong>desain 3D realistis</strong> serta rencana teknis yang meliputi <strong>denah, struktur, dan material yang akan digunakan</strong>.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">📌</span> 4. Finalisasi Desain &amp; Siap Dibangun</strong><br />\r\nSetelah semua detail disetujui, desain final akan kami serahkan lengkap dengan perhitungan teknis yang siap digunakan untuk proses pembangunan.</span></span></p>\r\n\r\n<div style=\"margin-bottom:11px; text-align:center\">&nbsp;</div>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>WUJUDKAN PROPERTI IMPIAN ANDA SEKARANG!</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Jangan biarkan proyek pembangunan atau renovasi Anda dilakukan tanpa perencanaan yang matang. Dengan jasa <strong>Design Arsitek profesional</strong> dari kami, Anda akan mendapatkan desain yang <strong>indah, nyaman, fungsional, dan bernilai investasi tinggi</strong>.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">📞</span> <strong>Hubungi kami sekarang</strong> untuk konsultasi dan penawaran terbaik!</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🌟</span> <strong>&quot;Desain yang baik bukan hanya soal estetika, tetapi bagaimana ruang dapat memberikan kenyamanan dan kehidupan bagi penghuninya.&quot;</strong> <span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🌟</span></span></span></p>', '087877799878', '2025-02-25 07:09:56', '2025-03-09 08:00:23'),
(3, 'Bangun Dan Renovasi', 'banner-service/zjnweTFymYr7pjwlPOqSeG3DrtVUHHsBXmWqD28o.png', 'Membangun & Merenovasi Properti Dengan Kualitas Dan Nilai Lebih', '<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Mewujudkan hunian impian atau properti yang berkualitas bukan sekadar tentang membangun, tetapi juga tentang <strong>memilih mitra yang tepat</strong>. Kami hadir untuk memberikan solusi terbaik dalam <strong>pembangunan dan renovasi</strong>, dengan standar material berkualitas, desain yang fungsional, dan pengerjaan yang profesional.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Anda ingin membangun rumah dari nol, memperbarui tampilan properti, atau meningkatkan fungsionalitas bangunan, kami menawarkan layanan yang <strong>terukur, transparan, dan bernilai tambah</strong>. Dengan tim ahli dan pengalaman di industri properti, kami memastikan setiap proyek selesai dengan hasil <strong>maksimal, tepat waktu, dan sesuai ekspektasi</strong>.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🚀</span> <strong>Mengapa Memilih Kami?</strong></span></span></p>\r\n\r\n<p><br />\r\n<span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">✅</span> <strong>Kualitas Terjamin</strong> &ndash; Material terbaik &amp; pengerjaan detail<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">✅</span> <strong>Desain Modern &amp; Fungsional</strong> &ndash; Estetika bertemu kenyamanan<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">✅</span> <strong>Budget Transparan</strong> &ndash; Perencanaan biaya yang jelas dan efisien<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">✅</span> <strong>Pengerjaan Profesional</strong> &ndash; Dikerjakan oleh tenaga ahli berpengalaman</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Jangan biarkan renovasi atau pembangunan menjadi beban. Bersama kami, wujudkan properti impian Anda dengan proses yang <strong>mudah, cepat, dan berkualitas tinggi</strong>. </span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>1. Pembangunan Properti &ndash; Wujudkan Hunian &amp; Investasi Impian</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Membangun rumah atau properti dari nol adalah sebuah perjalanan besar yang membutuhkan perencanaan matang dan eksekusi yang tepat. Kami hadir untuk membantu Anda dalam setiap tahap pembangunan, mulai dari <strong>perancangan konsep, pemilihan material, hingga proses konstruksi</strong> yang sesuai dengan standar terbaik.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Keunggulan Layanan Pembangunan Kami:</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">🏗</span> <strong>Desain Eksklusif &amp; Fungsional</strong> &ndash; Kami membantu mewujudkan desain yang <strong>modern, estetis, dan sesuai kebutuhan Anda</strong>.<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🔍</span> <strong>Kualitas Material Terbaik</strong> &ndash; Hanya menggunakan bahan berkualitas tinggi yang memastikan bangunan <strong>kokoh, tahan lama, dan bernilai investasi tinggi</strong>.<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">📋</span> <strong>Perencanaan Budget yang Transparan</strong> &ndash; Proses pembangunan yang <strong>terstruktur dengan anggaran yang jelas</strong>, tanpa biaya tersembunyi.<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🚀</span> <strong>Tim Profesional &amp; Berpengalaman</strong> &ndash; Dikerjakan oleh <strong>arsitek, insinyur, dan tenaga ahli</strong> yang siap mewujudkan properti impian Anda.<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">⏳</span> <strong>Tepat Waktu &amp; Efisien</strong> &ndash; Kami memastikan setiap proyek berjalan sesuai jadwal dan diselesaikan dengan <strong>hasil terbaik dalam waktu yang optimal</strong>.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Layanan pembangunan ini cocok bagi Anda yang ingin membangun:<br />\r\n<span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">✔</span> Rumah tinggal pribadi (minimalis, klasik, modern, mewah)<br />\r\n<span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">✔</span> Ruko atau bangunan komersial<br />\r\n<span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">✔</span> Villa &amp; resort dengan konsep eksklusif<br />\r\n<span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">✔</span> Kos-kosan atau properti investasi</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Proses Pembangunan Properti Bersama Kami:</strong></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">1️<span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">⃣</span> <strong>Konsultasi &amp; Perencanaan</strong> &ndash; Memahami kebutuhan Anda &amp; membuat konsep awal<br />\r\n2️<span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">⃣</span> <strong>Desain &amp; Estimasi Anggaran</strong> &ndash; Menyusun desain arsitektur &amp; perhitungan biaya<br />\r\n3️<span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">⃣</span> <strong>Pembangunan</strong> &ndash; Eksekusi proyek sesuai desain &amp; standar yang disepakati<br />\r\n4️<span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">⃣</span> <strong>Finishing &amp; Serah Terima</strong> &ndash; Penyempurnaan dan penyerahan hasil akhir yang siap dihuni</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🌟</span> <strong>Bangun properti impian Anda bersama tim profesional!</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>2. Renovasi Properti &ndash; Transformasi Hunian Menjadi Lebih Nyaman &amp; Berkelas</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Rumah atau properti yang sudah lama dihuni pasti memerlukan peremajaan agar tetap nyaman, fungsional, dan memiliki nilai estetika yang lebih tinggi. Kami menawarkan <strong>jasa renovasi menyeluruh</strong> yang dapat meningkatkan tampilan dan fungsi properti sesuai dengan keinginan Anda.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Layanan Renovasi yang Kami Tawarkan:</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🏡</span> <strong>Renovasi Ringan</strong> &ndash; Perbaikan kecil seperti pengecatan ulang, penggantian kusen, pintu, jendela, dan peremajaan interior.<br />\r\n<span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">🏗</span> <strong>Renovasi Sedang</strong> &ndash; Penggantian atap, lantai, dapur, kamar mandi, atau ruang tertentu tanpa mengubah struktur utama bangunan.<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🏠</span> <strong>Renovasi Besar</strong> &ndash; Perubahan tata letak, perluasan bangunan, atau transformasi total sesuai kebutuhan.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Keunggulan Layanan Renovasi Kami:</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🔹</span> <strong>Analisis Kebutuhan Detail</strong> &ndash; Kami memahami kebutuhan renovasi Anda untuk hasil yang <strong>efektif dan efisien</strong>.<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🔹</span> <strong>Desain Estetis &amp; Modern</strong> &ndash; Menyediakan konsep desain yang <strong>fungsional dan selaras dengan gaya arsitektur terkini</strong>.<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🔹</span> <strong>Material Berkualitas</strong> &ndash; Menggunakan material premium yang meningkatkan daya tahan dan estetika properti Anda.<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🔹</span> <strong>Biaya Transparan</strong> &ndash; Estimasi anggaran yang jelas tanpa tambahan biaya tersembunyi.<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🔹</span> <strong>Proses Cepat &amp; Tepat Waktu</strong> &ndash; Dikerjakan oleh tim profesional dengan pengerjaan <strong>rapi dan sesuai jadwal</strong>.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Proses Renovasi Bersama Kami:</strong></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">1️<span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">⃣</span> &nbsp;<strong>Survey &amp; Konsultasi</strong> &ndash; Analisis kondisi bangunan dan kebutuhan renovasi<br />\r\n2️<span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">⃣</span> &nbsp;<strong>Desain &amp; Perencanaan</strong> &ndash; Penyusunan konsep renovasi dan estimasi biaya<br />\r\n3️<span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">⃣</span> &nbsp;<strong>Pelaksanaan Renovasi</strong> &ndash; Eksekusi renovasi dengan pengawasan ketat<br />\r\n4️<span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">⃣</span> &nbsp;<strong>Finishing &amp; Serah Terima</strong> &ndash; Penyempurnaan dan pembersihan pasca-renovasi</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🎯</span> <strong>Jadikan properti Anda lebih modern, nyaman, dan bernilai tinggi dengan layanan renovasi kami!</strong></span></span></p>', '089977776467', '2025-02-25 09:51:11', '2025-03-09 07:45:31'),
(4, 'Alumunium Spesialis', 'banner-service/WJwiS02dw2iHUVWnGgCWl7KA4SEW8ZXwXBtzUd6K.png', 'Solusi Elegan Dan Modern Untuk Hunian Anda', '<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Kami memahami bahwa properti yang nyaman dan estetik bukan hanya tentang desain bangunan, tetapi juga detail interior dan eksterior yang berkualitas. Oleh karena itu, kami menghadirkan berbagai perangkat pendukung properti dengan material premium berbahan <strong>aluminium dan kaca</strong>, yang tidak hanya kuat dan tahan lama, tetapi juga memberikan kesan <strong>mewah dan modern</strong>.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Produk kami mencakup <strong>kitchen set, railing kaca tangga, toilet glass, kusen, pintu, jendela, kanopi, shower screen, dan kaca tempered</strong>&mdash;semua dirancang untuk meningkatkan kenyamanan dan nilai estetika properti Anda. Dengan desain yang elegan serta pengerjaan yang presisi, kami memastikan setiap produk memberikan nilai lebih bagi hunian maupun proyek Anda.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Produk Alumunium Kami :</span></span></strong></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>1. Kitchen Set &ndash; Fungsional dan Estetik dalam Satu Desain</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Dapur bukan hanya tempat memasak, tetapi juga jantung dari sebuah rumah. Dengan kitchen set berbahan <strong>aluminium dan kaca</strong>, kami menghadirkan desain modern yang tidak hanya tahan lama dan anti-rayap, tetapi juga mudah dibersihkan. Cocok untuk Anda yang menginginkan dapur yang <strong>mewah, bersih, dan efisien</strong>.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>2. Railing Kaca Tangga &ndash; Sentuhan Elegan untuk Hunian Anda</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Tambahkan kesan <strong>mewah dan minimalis</strong> pada rumah atau bangunan Anda dengan railing kaca tangga. Menggunakan kaca tempered berkualitas tinggi dan rangka aluminium yang kokoh, produk ini memberikan <strong>kesan luas, modern, dan aman</strong> bagi penghuni.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>3. Toilet Glass &ndash; Privasi dengan Gaya Modern</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Nikmati kamar mandi yang lebih eksklusif dengan toilet glass berbahan kaca tempered. Dengan desain transparan atau buram, toilet glass menciptakan suasana <strong>bersih, luas, dan elegan</strong>, memberikan kenyamanan lebih bagi setiap pengguna.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>4. Kusen Aluminium &ndash; Ringan, Kokoh, dan Tahan Lama</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Gantilah kusen konvensional Anda dengan kusen aluminium berkualitas tinggi. <strong>Anti-rayap, tahan karat, dan memiliki desain modern</strong>, kusen aluminium cocok untuk segala jenis bangunan, baik hunian, kantor, maupun komersial.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>5. Pintu Aluminium &amp; Kaca &ndash; Kombinasi Keindahan dan Ketahanan</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Pintu dengan material aluminium dan kaca menawarkan <strong>desain modern, daya tahan tinggi, serta perawatan yang mudah</strong>. Ideal untuk area dalam maupun luar ruangan, memberikan kesan eksklusif pada setiap ruangan.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>6. Jendela Aluminium &ndash; Sirkulasi Udara Maksimal, Estetika Optimal</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Jendela aluminium dirancang untuk memberikan pencahayaan alami dan sirkulasi udara yang maksimal. Dengan material yang <strong>kuat, ringan, dan anti-karat</strong>, jendela ini menjadi pilihan terbaik untuk hunian modern.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>7. Kanopi Aluminium &amp; Kaca &ndash; Perlindungan dengan Gaya Minimalis</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Lindungi area eksterior rumah Anda dengan kanopi berbahan aluminium dan kaca. Tidak hanya memberikan perlindungan dari cuaca, tetapi juga menciptakan tampilan <strong>elegan dan futuristik</strong> untuk teras atau carport Anda.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>8. Shower Screen &ndash; Kamar Mandi Lebih Nyaman dan Modern</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Shower screen kaca tempered memberikan <strong>privasi, estetika, dan perlindungan dari cipratan air</strong>. Desainnya yang minimalis dan elegan menjadikan kamar mandi terasa lebih luas dan mewah.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>9. Kaca Tempered &ndash; Keamanan dan Keindahan dalam Satu Material</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Kaca tempered memiliki daya tahan lebih kuat dibandingkan kaca biasa, membuatnya lebih aman dan tahan terhadap benturan. Cocok digunakan untuk berbagai kebutuhan seperti partisi, railing, hingga pintu kaca.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Jadikan rumah atau properti Anda lebih <strong>eksklusif dan berkelas</strong> dengan produk berkualitas dari kami. Hubungi kami sekarang untuk informasi lebih lanjut dan konsultasi gratis!</span></span></p>', '0811667545', '2025-02-25 10:05:12', '2025-03-09 07:31:41'),
(5, 'Pengukuran Tanah', 'banner-service/C3nHTKnVizJ6mIxIJwDpbqi4CRUYk9bLOc8KYze0.png', 'Layanan Pengukuran Tanah Profesional – Pastikan Legalitas & Akurasi Properti Anda', '<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Mengapa Pengukuran Tanah Sangat Penting?</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><br />\r\n<span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Dalam transaksi dan pengembangan properti, <strong>kesalahan dalam pengukuran tanah dapat berdampak besar</strong>, baik dari segi <strong>legalitas, perencanaan pembangunan, maupun nilai investasi</strong>. Tanah yang tidak sesuai dengan dokumen sertifikat bisa menyebabkan <strong>sengketa, kehilangan aset, atau kerugian finansial yang besar</strong>.</span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Karena itulah, kami menghadirkan layanan <strong>Pengukuran Tanah &amp; Surveyor Profesional</strong> untuk membantu perorangan maupun developer kecil, menengah, dan besar memastikan bahwa <strong>luas tanah yang akan dibeli atau dikembangkan benar-benar sesuai dengan kondisi nyata</strong> di lapangan.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>KEUNGGULAN LAYANAN PENGUKURAN TANAH KAMI</strong></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">📍</span> <strong>Akurasi Tinggi &amp; Teknologi Modern</strong><br />\r\nKami menggunakan metode pengukuran terkini untuk memastikan bahwa luas dan batas tanah sesuai dengan kondisi real. Ini penting untuk <strong>menghindari kesalahan perhitungan</strong> yang dapat berdampak pada harga jual dan pengembangan properti Anda.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">📍</span> <strong>Memastikan Kesesuaian dengan Dokumen Legal</strong><br />\r\nBanyak kasus di mana <strong>luas tanah di sertifikat tidak sesuai dengan kondisi di lapangan</strong>. Dengan pengukuran profesional, Anda bisa mengetahui <strong>ukuran sebenarnya sebelum melakukan pembelian atau pengembangan</strong>.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">📍</span> <strong>Menghindari Potensi Sengketa Lahan</strong><br />\r\nPerbedaan luas tanah yang tidak terdeteksi sejak awal dapat menimbulkan masalah hukum di kemudian hari. Layanan kami membantu Anda <strong>mencegah konflik dengan pihak lain</strong>, baik itu tetangga, pengembang lain, maupun instansi pemerintah.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">📍</span> <strong>Laporan Lengkap &amp; Terperinci</strong><br />\r\nKami menyediakan laporan hasil pengukuran yang <strong>jelas, detail, dan mudah dipahami</strong>, termasuk peta lahan dan titik koordinat yang dapat menjadi referensi resmi.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">📍</span> <strong>Mendukung Perencanaan Pembangunan</strong><br />\r\nBagi pengembang properti, pengukuran tanah sangat penting untuk <strong>merencanakan tata letak bangunan, infrastruktur, dan fasilitas lainnya secara optimal</strong>. Kesalahan dalam luas lahan bisa menyebabkan <strong>biaya tambahan dan revisi besar dalam konstruksi</strong>.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">📍</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"> <strong>Cocok untuk Semua Skala &amp; Kebutuhan</strong><br />\r\nLayanan kami tersedia untuk berbagai keperluan, mulai dari:</span></span><br />\r\n<span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">✅</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"> <strong>Individu</strong> &ndash; Pastikan tanah yang Anda beli sesuai dengan sertifikat dan tidak ada kesalahan pengukuran.</span></span><br />\r\n<span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">✅</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"> <strong>Developer &amp; Kontraktor</strong> &ndash; Hindari kesalahan dalam perencanaan proyek dengan data lahan yang akurat.</span></span><br />\r\n<span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">✅</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"> <strong>Perusahaan &amp; Institusi</strong> &ndash; Pastikan legalitas aset properti Anda sesuai dengan data lapangan yang valid.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>PROSES PENGUKURAN TANAH BERSAMA KAMI</strong></span></span></p>\r\n\r\n<p><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">1️</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">⃣</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"> <strong>Konsultasi Awal</strong> &ndash; Kami akan memahami kebutuhan Anda dan memberikan saran terbaik sesuai dengan tujuan pengukuran.</span></span></p>\r\n\r\n<p><br />\r\n<span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">2️</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">⃣</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"> <strong>Survey Lapangan</strong> &ndash; Tim surveyor kami akan melakukan pengukuran menggunakan teknologi presisi tinggi.</span></span></p>\r\n\r\n<p><br />\r\n<span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">3️</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">⃣</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"> <strong>Analisis &amp; Verifikasi Data</strong> &ndash; Kami memastikan bahwa hasil pengukuran sesuai dengan dokumen legal yang ada.</span></span></p>\r\n\r\n<p><br />\r\n<span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">4️</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">⃣</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"> <strong>Penyusunan Laporan &amp; Peta Tanah</strong> &ndash; Hasil pengukuran disajikan dalam bentuk laporan yang detail dan mudah dipahami.</span></span></p>\r\n\r\n<p><br />\r\n<span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">5️</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">⃣</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"> <strong>Penyerahan Data &amp; Konsultasi Akhir</strong> &ndash; Anda akan mendapatkan semua dokumen hasil pengukuran, serta konsultasi tambahan jika diperlukan</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>JANGAN AMBIL RISIKO DENGAN DATA TANAH YANG TIDAK AKURAT!</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🔍</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"> <strong>Pastikan tanah Anda memiliki ukuran yang sesuai sebelum mengambil keputusan besar.</strong> Layanan kami hadir untuk <strong>melindungi investasi properti Anda, mencegah masalah di masa depan, dan memastikan semua perencanaan berjalan lancar</strong>.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">📞</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"> <strong>Hubungi kami sekarang</strong> untuk layanan pengukuran tanah yang presisi, cepat, dan terpercaya!</span></span></p>', '08222377876', '2025-02-25 12:05:09', '2025-04-20 15:21:32'),
(6, 'Manpower Konstruksi', 'banner-service/dhLR0EQ5PrOWYu47jVn2PYYEuooRFxDu3zlBHnuj.png', 'Layanan Manpower Profesional – Solusi Tenaga Kerja Andal untuk Konstruksi Anda', '<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Dalam industri konstruksi, <strong>tenaga kerja yang handal dan berkualitas adalah faktor utama</strong> dalam menentukan kelancaran dan keberhasilan sebuah proyek. Kami menyediakan <strong>layanan Manpower profesional</strong> untuk mendukung proyek <strong>pembangunan skala kecil hingga menengah</strong>, dengan kapasitas suplai tenaga kerja hingga <strong>300 orang</strong>, sesuai dengan kebutuhan proyek Anda.</span></span></p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🔨</span> <strong>Tenaga kerja berpengalaman</strong> &ndash; Terlatih dan siap bekerja dengan efisiensi tinggi<br />\r\n<span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">🏗</span> <strong>Fleksibel &amp; skalabel</strong> &ndash; Bisa disesuaikan dengan kebutuhan proyek Anda<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">⏳</span> <strong>Hemat waktu &amp; biaya</strong> &ndash; Tidak perlu repot mencari tenaga kerja sendiri<br />\r\n<span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">✅</span> <strong>Dukungan penuh untuk pengembang &amp; institusi</strong> &ndash; Solusi tenaga kerja yang siap pakai untuk konstruksi, renovasi, dan infrastruktur</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Dengan layanan Manpower kami, Anda bisa <strong>fokus pada perencanaan dan eksekusi proyek</strong>, tanpa perlu khawatir tentang ketersediaan tenaga kerja. <strong>Hubungi kami sekarang</strong> dan pastikan proyek Anda berjalan lancar dengan tenaga kerja yang andal dan berkualitas.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>KENAPA MEMILIH LAYANAN MANPOWER KAMI?</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">✔</span> <strong>Tenaga Kerja Berpengalaman &amp; Terlatih</strong><br />\r\nKami hanya menyediakan tenaga kerja yang telah memiliki pengalaman dan keterampilan dalam bidang konstruksi. Mulai dari <strong>tukang bangunan, pekerja kasar, mandor, hingga spesialis finishing</strong>, tim kami siap mendukung proyek Anda dengan hasil yang berkualitas.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">✔</span> <strong>Fleksibel &amp; Skalabel Sesuai Kebutuhan</strong><br />\r\nKami memahami bahwa setiap proyek memiliki skala dan kompleksitas yang berbeda. Oleh karena itu, kami menyediakan <strong>tenaga kerja dalam jumlah yang dapat disesuaikan</strong>, mulai dari <strong>tim kecil untuk proyek renovasi hingga ratusan pekerja untuk proyek pembangunan skala besar</strong>.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">✔</span> <strong>Meningkatkan Efisiensi &amp; Produktivitas Proyek</strong><br />\r\nDengan tenaga kerja yang terorganisir dan profesional, proyek Anda akan berjalan <strong>lebih cepat dan efisien</strong>, mengurangi risiko keterlambatan serta meningkatkan kualitas hasil akhir konstruksi.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">✔</span> <strong>Pengelolaan SDM yang Mudah &amp; Bebas Repot</strong><br />\r\nKami menangani <strong>rekrutmen, administrasi, dan koordinasi tenaga kerja</strong>, sehingga Anda bisa <strong>fokus pada strategi dan eksekusi proyek tanpa harus mengurus detail operasional tenaga kerja</strong>.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">✔</span> <strong>Membantu Mengoptimalkan Biaya Proyek</strong><br />\r\nMerekrut tenaga kerja sendiri membutuhkan waktu dan biaya tambahan. Dengan layanan Manpower kami, Anda mendapatkan <strong>tenaga kerja siap pakai tanpa perlu memikirkan biaya rekrutmen, pelatihan, dan administrasi</strong>.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">✔</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"> <strong>Dukungan untuk Berbagai Jenis Proyek Konstruksi</strong><br />\r\nLayanan Manpower kami cocok untuk berbagai jenis proyek, termasuk:</span></span><br />\r\n<span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">🏗</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"> <strong>Pembangunan rumah tinggal</strong> &ndash; Baik rumah pribadi maupun proyek perumahan</span></span><br />\r\n<span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🏢</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"> <strong>Konstruksi komersial</strong> &ndash; Seperti ruko, kantor, dan showroom</span></span><br />\r\n<span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">🏠</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"> <strong>Renovasi &amp; perluasan bangunan</strong> &ndash; Mulai dari perbaikan kecil hingga renovasi total</span></span><br />\r\n<span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">🛠</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"> <strong>Pemasangan &amp; finishing</strong> &ndash; Meliputi pemasangan lantai, dinding, atap, serta pekerjaan finishing lainnya</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>PROSES LAYANAN MANPOWER KAMI</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>1️</strong><strong><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">⃣</span> Konsultasi Kebutuhan</strong><br />\r\nKami akan mendiskusikan kebutuhan tenaga kerja Anda, termasuk jumlah, keterampilan, dan durasi proyek.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>2️</strong><strong><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">⃣</span> Pemilihan &amp; Penyediaan Tenaga Kerja</strong><br />\r\nKami akan menyiapkan tenaga kerja sesuai permintaan Anda, baik untuk kebutuhan harian, mingguan, atau proyek jangka panjang.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>3️</strong><strong><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">⃣</span> Pengerjaan &amp; Monitoring Kinerja</strong><br />\r\nTim kami akan bekerja sesuai instruksi yang diberikan, dengan supervisi dan evaluasi kinerja yang memastikan proyek berjalan sesuai rencana.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">4️</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif\">⃣</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"> Penyelesaian &amp; Evaluasi Proyek</span></span></strong><br />\r\n<span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Setelah proyek selesai, kami akan melakukan evaluasi bersama untuk memastikan hasil kerja memenuhi standar yang diharapkan.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>DAPATKAN TENAGA KERJA PROFESIONAL UNTUK PROYEK ANDA!</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">📌</span> <strong>Jangan biarkan proyek Anda terhambat karena keterbatasan tenaga kerja.</strong> Dengan layanan Manpower kami, Anda akan mendapatkan <strong>tim yang siap bekerja, terlatih, dan berkualitas</strong> sesuai dengan kebutuhan proyek Anda.</span></span></p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">📞</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"> <strong>Hubungi kami sekarang</strong> untuk solusi tenaga kerja yang andal dan efisien!</span></span></p>', '08118843578', '2025-02-25 14:43:12', '2025-03-09 08:06:07');
INSERT INTO `services` (`id`, `judul`, `image`, `short_desc`, `long_desc`, `no_hp`, `created_at`, `updated_at`) VALUES
(7, 'Kerjasama Lahan', 'banner-service/CCCWIC6530aRlBorQP3BBInGmxoesl4Ne5RP6Pho.png', 'Ubah Tanah Menganggur Menjadi Aset Bernilai Tinggi', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Punya Lahan yang Sulit Terjual? Mari Bekerjasama!</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Apakah Anda memiliki lahan yang luas tetapi sulit terjual? Atau ingin memaksimalkan keuntungan tanpa harus menjualnya langsung? Kami menawarkan solusi terbaik melalui <strong>Sistem Kerjasama Lahan</strong>. Dengan skema ini, tanah Anda akan dikembangkan menjadi properti bernilai tinggi yang dapat menghasilkan keuntungan lebih besar.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Apa Itu Kerjasama Lahan?</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Kerjasama lahan adalah konsep di mana pemilik tanah yang memiliki lahan kurang produktif atau sulit dijual dapat bekerja sama dengan kami untuk pengembangannya. Lahan tersebut akan dikonversi menjadi proyek properti yang memiliki nilai jual lebih tinggi, seperti <strong>cluster perumahan, rumah eksklusif, atau properti komersial</strong>. Setelah pembangunan selesai, properti ini akan dipasarkan oleh tim profesional kami.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Keuntungan Bekerjasama dengan Kami</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">✅</span> <strong>Tanah Anda Menjadi Produktif</strong><br />\r\nDaripada lahan Anda dibiarkan kosong atau sulit terjual, kami akan mengubahnya menjadi properti yang menarik bagi pembeli. Ini akan meningkatkan nilai investasi tanah Anda secara signifikan.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">✅</span> <strong>Minim Risiko dan Bebas Repot</strong><br />\r\nKami menangani seluruh proses mulai dari perencanaan, perizinan, desain arsitektur, konstruksi, hingga pemasaran. Anda tidak perlu pusing mengurus detail teknis.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">✅</span> <strong>Skema Kerjasama yang Transparan dan Menguntungkan</strong><br />\r\nKami menawarkan skema pembagian keuntungan yang jelas dan saling menguntungkan bagi kedua belah pihak. Dengan sistem ini, Anda tetap memiliki hak atas lahan dan menikmati hasil dari properti yang terjual.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">✅</span> <strong>Dukungan Tim Profesional</strong><br />\r\nKami memiliki pengalaman dalam pengembangan properti, mulai dari <strong>tim arsitek, kontraktor, tenaga kerja konstruksi, hingga tim pemasaran yang siap menjual properti Anda secara efektif.</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Bagaimana Prosesnya?</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<ol>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Konsultasi &amp; Analisis Lahan</strong><br />\r\n	Kami akan melakukan analisis mendalam terhadap lokasi dan potensi pengembangan lahan Anda.</span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Perencanaan &amp; Perizinan</strong><br />\r\n	Bersama tim ahli, kami akan merancang konsep pembangunan terbaik dan mengurus legalitasnya.</span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Pembangunan Properti</strong><br />\r\n	Kami akan mulai membangun sesuai dengan konsep yang disepakati.</span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Pemasaran &amp; Penjualan</strong><br />\r\n	Tim pemasaran kami akan memastikan properti terjual dengan strategi digital dan offline terbaik.</span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Pembagian Keuntungan</strong><br />\r\n	Keuntungan dari hasil penjualan akan dibagi sesuai kesepakatan yang telah dibuat sejak awal.</span></span></li>\r\n</ol>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Siapa yang Cocok Menggunakan Layanan Ini?</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<ul>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Pemilik tanah yang lahannya sulit dijual karena terlalu luas atau tidak strategis.</span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Pemilik lahan yang ingin mendapatkan keuntungan lebih dari sekadar menjual tanah kosong.</span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Investor properti yang ingin mengembangkan tanahnya tanpa harus mengeluarkan modal besar.</span></span></li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Mari Wujudkan Properti Impian di Atas Tanah Anda!</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Kami siap menjadi mitra strategis Anda dalam mengoptimalkan aset properti. Jika Anda tertarik untuk mengetahui lebih lanjut mengenai skema kerjasama ini, <strong>hubungi kami sekarang! </strong>Untuk<strong> </strong>lokasi<strong> </strong>saat<strong> </strong>ini<strong> </strong>kami<strong> </strong>batasi<strong> </strong>wilayah<strong> di Jakarta, Depok, Tangerang.&nbsp;</strong>Diluar lokasi tersebut perlu kami riset terlebih dahulu.&nbsp;</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">📩</span></span><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"> <strong>Konsultasi Gratis!</strong></span></span><br />\r\n&nbsp;</p>', '087854454888', '2025-02-26 04:21:47', '2026-02-16 14:32:22'),
(8, 'Pembiayaan KPR', 'banner-service/7rLjc9nIl0YCvKE2wOr0QtfziE9FeYurwX3hlN37.png', 'Mau Punya Rumah Impian Tapi Bingung Urus KPR?', '<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Pengurusan KPR Bank &ndash; Wujudkan Rumah Impian Tanpa Ribet!</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Mengapa Perlu Bantuan Pengurusan KPR?</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Membeli rumah adalah impian banyak orang, tetapi proses pengajuan <strong>KPR (Kredit Pemilikan Rumah)</strong> sering kali membingungkan dan memakan waktu. Banyak calon pembeli yang mengalami kendala seperti <strong>persyaratan dokumen yang rumit, proses pengajuan yang lama, hingga pengajuan yang ditolak oleh bank</strong>. Oleh karena itu, kami hadir untuk memberikan solusi terbaik agar Anda bisa mendapatkan rumah impian dengan lebih mudah dan cepat!</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Keuntungan Menggunakan Jasa Pengurusan KPR Kami</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">✅</span> <strong>Panduan Lengkap dari Awal Hingga Disetujui</strong><br />\r\nKami mendampingi Anda dari tahap awal, mulai dari persiapan dokumen, pemilihan bank, hingga proses persetujuan dan pencairan kredit.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">✅</span> <strong>Koneksi dengan Berbagai Bank</strong><br />\r\nKami bekerja sama dengan berbagai bank ternama untuk memastikan Anda mendapatkan <strong>suku bunga terbaik dan skema cicilan yang paling sesuai dengan kondisi finansial Anda</strong>.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">✅</span> <strong>Simulasi KPR Gratis</strong><br />\r\nKami menyediakan layanan konsultasi untuk membantu Anda memahami <strong>berapa besar cicilan per bulan, tenor yang cocok, dan biaya tambahan yang perlu dipersiapkan</strong>.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">✅</span> <strong>Mempermudah Proses &amp; Meminimalkan Penolakan</strong><br />\r\nBanyak pengajuan KPR ditolak karena dokumen yang tidak lengkap atau skor kredit yang kurang memenuhi syarat. Dengan pengalaman kami, kami akan membantu memastikan <strong>persyaratan Anda sesuai dengan ketentuan bank</strong>, sehingga peluang persetujuan lebih tinggi.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">✅</span> <strong>Hemat Waktu &amp; Bebas Ribet</strong><br />\r\nDaripada bolak-balik mengurus dokumen dan mengikuti prosedur yang panjang, serahkan semuanya kepada kami dan fokus pada pemilihan rumah yang sesuai dengan keinginan Anda.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Bagaimana Proses Pengurusan KPR dengan Kami?</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<ol>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Konsultasi Awal &amp; Analisis Finansial</strong><br />\r\n	Kami akan mengevaluasi kondisi finansial Anda dan memberikan rekomendasi bank terbaik yang sesuai dengan kebutuhan Anda.</span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Persiapan Dokumen</strong><br />\r\n	Kami membantu mengumpulkan dan memastikan semua dokumen yang diperlukan lengkap, termasuk slip gaji, laporan keuangan, dan persyaratan lainnya.</span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Pemilihan Skema KPR yang Sesuai</strong><br />\r\n	Kami akan memberikan opsi bank dengan suku bunga, tenor, dan sistem pembayaran terbaik untuk Anda.</span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Pengajuan ke Bank</strong><br />\r\n	Kami mengajukan aplikasi KPR ke bank pilihan dan memastikan semua prosedur berjalan lancar.</span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Proses Verifikasi &amp; Persetujuan</strong><br />\r\n	Bank akan melakukan penilaian kelayakan, termasuk survei rumah dan analisis kredit, hingga akhirnya memberikan keputusan persetujuan.</span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Pencairan Kredit &amp; Akad KPR</strong><br />\r\n	Setelah KPR disetujui, Anda akan masuk ke tahap pencairan dana dan akad kredit dengan pihak bank.</span></span></li>\r\n</ol>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Siapa yang Cocok Menggunakan Layanan Ini?</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<ul>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Calon pembeli rumah pertama yang belum pernah mengajukan KPR dan butuh panduan.</span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Pembeli properti yang ingin mendapatkan suku bunga dan tenor terbaik.</span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Pekerja dengan status <strong>freelancer atau wiraswasta</strong> yang kesulitan mendapatkan persetujuan KPR.</span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Konsumen yang ingin menghindari proses administrasi yang rumit dan panjang.</span></span></li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><strong>Bersama Kami, Proses KPR Jadi Lebih Mudah!</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\">Kami memahami bahwa setiap calon pembeli memiliki kondisi finansial yang berbeda. Oleh karena itu, kami menawarkan layanan yang fleksibel dan personal untuk memastikan Anda mendapatkan solusi terbaik.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">📩</span> <strong>Konsultasi Gratis!</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Jangan biarkan proses pengajuan KPR menjadi penghalang memiliki rumah impian. <strong>Serahkan kepada kami, dan wujudkan hunian terbaik untuk Anda dan keluarga</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-family:&quot;Segoe UI Emoji&quot;,sans-serif\">📩<strong>DISCLAIMER</strong>&nbsp;</span></span></span></p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><strong><span style=\"font-size:11.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Kami tidak melayani permintaan manimulatif data dengan cara apapun. Data yang disampaikan kepada kami harus data real konsumen dan sesungguhnya.&nbsp;&nbsp;</span></span></strong></p>', '087854454888', '2025-02-26 15:25:13', '2025-12-26 07:17:00');
