(3, 'Agam', '085814268525', 'Lebak Bulus', 'Beli', 'Rumah', 'Depok', 'Depok Sawangan', '400.000.000', '<p>Cari Rumah bisa KPR sekitar Depok, tidak jauh dari pondok labu. Dalam cluster, 1 lantai ngga masalah</p>', 'Tampilkan', 'Closed', '2025-03-14 11:41:36', '2025-09-09 05:22:20'),
(8, 'Kevin', '085891424438', 'Lebak Lubus', 'Beli', 'Rumah', 'Tangerang', 'Ciputat Bintaro', '800.000.000', '<p>Cari Rumah skitar bintaro, ciputat, Pondok Aren. Budget range 600 sd 800jt. Rencana KPR atau cash.</p>', 'Tampilkan', 'Available', '2025-03-14 15:33:04', '2025-03-14 15:45:22'),
(9, 'Dani', '087789494045', 'Tangsel', 'Sewa', 'Rumah', 'Tangerang', 'Tangsel, Ciputat, Serua', '20.000.000', '<p>Informasi Sewa Rumah 20jt / tahun, sekitar&nbsp;Tangsel, Ciputat, Serua</p>', 'Tampilkan', 'Available', '2025-04-08 08:00:53', '2025-04-08 08:18:11'),
(10, 'Yudi', '081298598245', 'Jakarta Pusat', 'Beli', 'Rumah', 'Tangerang', 'Ciputat Pamulang', '500.000.000', '<p>Cari Rumah Baru sekitar Ciputat, Pamulang Harga 500 jt-an, rencana mau beli cash.</p>', 'Tampilkan', 'Closed', '2025-04-11 02:39:55', '2025-05-02 03:13:31'),
(12, 'Arief', '08125121526', 'Bintaro Jakarta Selatan', 'Beli', 'Rumah', 'Tangerang', 'JakSel Tangsel', '1.500.000.000', '<p>Cari rumah Dalam Perumahan sekitar bintaro Jaya. Boleh Non Jaya selama dalam cluster atau townhouse.</p>', 'Tampilkan', 'Closed', '2025-06-01 00:53:53', '2025-10-23 13:51:36'),
(13, 'Uni Liz', '081315824473', 'Jakarta Selatan', 'Beli', 'Rumah', 'Tangerang', 'Area Tangsel Dan Depok', '800.000.000', '<p>Lokasi rumah tidak jauh Dari jaksel, area Tangsel Dan Depok. Spek 3 kamar, dengan pembiayaan Syariah, Tanpa DP</p>', 'Tampilkan', 'Closed', '2025-08-24 02:26:43', '2025-10-23 13:52:06');
